update.foreach:
UPDATE my_mall.goods
SET stock_num = stock_num - #{item.count}
WHERE id = #{item.id}
  AND stock_num >= #{item.count}

UPDATE my_mall.goods
SET stock_num = stock_num + #{item.count}
WHERE id = #{item.id}
